ssimtbl = horzcat(table((1:nItersIht).','VariableNames',"Iterations"),ssimtbl);

% 辞書ファミリ(DCT/PCA/RICA/K-SVD/NSOLT)ごとに色を、正規化の有無で線種(実線/破線)を
