        'LineWidth',2,'Color',lineSpecs{iDic,1},'LineStyle',lineSpecs{iDic,2}, ... %[output:9c905809]
        'DisplayName',dicnames(iDic)) %[output:9c905809]
end
hold off %[output:9c905809]
xlabel('Iterations') %[output:9c905809]
ylabel('SSIM') %[output:9c905809]
